#!/bin/bash
echo "Dummy userdata logic is being executed......"
dnf install -y nginx
systemctl enable amazon-ssm-agent
systemctl enable nginx
systemctl start nginx
# Get the EC2 instance's private IP using IMDSv2 (requires token)
TOKEN=$(curl -X PUT "http://169.254.169.254/latest/api/token" -H "X-aws-ec2-metadata-token-ttl-seconds: 21600")
PRIVATE_IP=$(curl -s -H "X-aws-ec2-metadata-token: $TOKEN" http://169.254.169.254/latest/meta-data/local-ipv4)

cat <<EOF > /etc/nginx/conf.d/custom_8080.conf
server {
    listen 8080;
    server_name localhost;

    location / {
        root /usr/share/nginx/html;
        index index.html;
    }
}
EOF
# Customize the Nginx welcome page to include IP info
echo "<html><body><h1>Welcome from EC2!</h1><p>Private IP: $PRIVATE_IP</p></body></html>" > /usr/share/nginx/html/index.html
# Reload Nginx to apply new config
systemctl restart nginx
echo "User data script executed successfully."

agent_configurations.description:
Map of agent configurations to apply. Supported agents:
- cloudwatch: Amazon CloudWatch Agent

Example:
{
  cloudwatch = {
    logs = {
      logs_collected = {
        files = {
          collect_list = [
            {
              file_path = "/var/log/myapp/application.log"
              log_group_name = "/app/npd1/dummy-app/web-server/app"
              log_stream_name = "{instance_id}/application"
              retention_in_days = 30
            }
          ]
        }
      }
    }
  }
}
